import React from 'react';
import { Button, LabelMoney, Slideout } from '@linm-soft-org/linm-web-common-components';
import type { LinkedCashReceiptSummaryDto } from '../../services/bh/models';
import styles from '../../styles/documentForm.module.css';

export type LinkedReceiptSlideoutProps = {
  isOpen: boolean;
  onClose: () => void;
  receipts: LinkedCashReceiptSummaryDto[];
  onOpenReceipt: (receipt: LinkedCashReceiptSummaryDto) => void;
  testIdPrefix: string;
};

export const LinkedReceiptSlideout: React.FC<LinkedReceiptSlideoutProps> = ({
  isOpen,
  onClose,
  receipts,
  onOpenReceipt,
  testIdPrefix,
}) => {
  const footer = (
    <div className={styles.modalActions}>
      <Button variant="secondary" onClick={onClose} data-testid={`${testIdPrefix}-linked-receipt-close`}>
        Đóng
      </Button>
    </div>
  );

  return (
    <Slideout
      isOpen={isOpen}
      onClose={onClose}
      title="Phiếu thu liên kết"
      width="min(720px, 92vw)"
      customFooter={footer}
      data-testid={`${testIdPrefix}-linked-receipt-slideout`}
    >
      {receipts.length === 0 ? (
        <p data-testid={`${testIdPrefix}-linked-receipt-empty`}>Chưa có phiếu thu liên kết.</p>
      ) : (
        <div className={styles.tableWrapper}>
          <table className={styles.linesTable}>
            <thead>
              <tr>
                <th>Số PT</th>
                <th>Kênh TT</th>
                <th>Số tiền</th>
                <th />
              </tr>
            </thead>
            <tbody>
              {receipts.map((r, idx) => (
                <tr key={r.id} data-testid={`${testIdPrefix}-linked-receipt-row-${idx}`}>
                  <td>{r.code}</td>
                  <td>{r.paymentChannelName ?? r.paymentChannelCode ?? '—'}</td>

                  <td style={{ textAlign: 'right' }}><LabelMoney layout="value" variant="cell" value={r.amount} /></td>
                  <td>
                    <Button
                      variant="secondary"
                      type="button"
                      data-testid={`${testIdPrefix}-linked-receipt-open-${idx}`}
                      onClick={() => onOpenReceipt(r)}
                    >
                      Mở phiếu thu
                    </Button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </Slideout>
  );
};
