/** FM POS legacy — show when LegacyCode differs from Linm invoice code. */
export function resolveFmLegacyCodeDisplay(
  voucherCode: string,
  legacyCode?: string | null,
): string | null {
  const lc = legacyCode?.trim();
  if (!lc || lc === voucherCode.trim()) return null;
  return lc;
}
